composeOverride:
# Generated by McHarbor App Store
services:
  {{serviceName}}:
    image: {{image}}
    container_name: {{containerName}}
    restart: unless-stopped
    depends_on:
      - {{serviceName}}-db
{{ports}}
    volumes:
      - {{env.MOODLE_DATA_PATH}}:/bitnami/moodle
      - {{env.MOODLE_DATAFILES_PATH}}:/bitnami/moodledata
    environment:
      ALLOW_EMPTY_PASSWORD: "no"
      MOODLE_DATABASE_HOST: {{serviceName}}-db
      MOODLE_DATABASE_PORT_NUMBER: "3306"
      MOODLE_DATABASE_NAME: {{env.MOODLE_DB_NAME}}
      MOODLE_DATABASE_USER: {{env.MOODLE_DB_USER}}
      MOODLE_DATABASE_PASSWORD: {{env.MOODLE_DB_PASSWORD}}
  {{serviceName}}-db:
    image: mariadb:11
    container_name: {{containerName}}-db
    restart: unless-stopped
    volumes:
      - {{env.MOODLE_DB_PATH}}:/var/lib/mysql
    environment:
      MARIADB_DATABASE: {{env.MOODLE_DB_NAME}}
      MARIADB_USER: {{env.MOODLE_DB_USER}}
      MARIADB_PASSWORD: {{env.MOODLE_DB_PASSWORD}}
      MARIADB_ROOT_PASSWORD: {{env.MOODLE_DB_ROOT_PASSWORD}}
